if (!$json.id) {
  return [
    {
      json: {
        success: false,
        html: `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Invalid Confirmation Link | SyStack</title>
  ${styles}
</head>
<body>
  <main class="page">
    <div class="brand">SyStack</div>

    <section class="card">
      <div class="icon error">!</div>
      <h1>Link not valid</h1>
      <p class="subtitle">
        This confirmation link is invalid or expired. Please contact the business directly to confirm your appointment.
      </p>
    </section>

    <div class="footer-note">Automated booking powered by SyStack</div>
  </main>
</body>
</html>`
      }
    }
  ];
}

const customerName = escapeHtml($json.customer_name);
const service = escapeHtml($json.service);
const appointmentTime = formatAppointmentTime($json.appointment_time);

return [
  {
    json: {
      success: true,
      booking_id: $json.id,
      customer_name: $json.customer_name,
      email: $json.email,
      service: $json.service,
      appointment_time: $json.appointment_time,
      status: $json.status,
      confirmed: $json.confirmed,
      html: `<!DOCTYPE html>
